class Solution:
    def maxTurbulenceSize(self, arr):
        """
        :type arr: List[int]
        :rtype: int
        """
        if len(arr) <= 1:
            return len(arr)

        max_len = 1
        current_len = 1

        for i in range(1, len(arr)):
            # Skip equal adjacent elements
            if arr[i] == arr[i-1]:
                current_len = 1
                continue

            # Check if signs alternate
            if i >= 2:
                # (arr[i-1] - arr[i-2]) and (arr[i] - arr[i-1]) should have opposite signs
                if (arr[i-1] - arr[i-2]) * (arr[i] - arr[i-1]) < 0:
                    current_len += 1
                else:
                    current_len = 2
            else:
                current_len += 1

            max_len = max(max_len, current_len)

        return max_len
